import React, { useState } from 'react';

// Fake API: resolves ~90% of the time so you can see rollback occasionally.
function fakeLike() {
  return new Promise((resolve, reject) => {
    setTimeout(() => (Math.random() < 0.9 ? resolve() : reject(new Error('network'))), 400);
  });
}

export default function LikeButton({ initialCount = 0 }) {
  const [liked, setLiked] = useState(false);
  const [count, setCount] = useState(initialCount);
  const [busy, setBusy] = useState(false);
  const [pop, setPop] = useState(false);
  const [error, setError] = useState(false);

  const toggle = async () => {
    if (busy) return;
    const prevLiked = liked;
    const prevCount = count;

    const next = !liked;
    setLiked(next);
    setCount((c) => c + (next ? 1 : -1));
    setError(false);
    if (next) {
      setPop(true);
      setTimeout(() => setPop(false), 200);
    }

    setBusy(true);
    try {
      await fakeLike();
    } catch {
      setLiked(prevLiked);
      setCount(prevCount);
      setError(true);
    } finally {
      setBusy(false);
    }
  };

  return (
    <div>
      <button
        onClick={toggle}
        aria-pressed={liked}
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 8,
          padding: '8px 16px',
          fontSize: 16,
          cursor: busy ? 'wait' : 'pointer',
          border: '1px solid #e5e7eb',
          borderRadius: 999,
          background: liked ? '#fee2e2' : '#fff',
          color: liked ? '#dc2626' : '#374151',
          transform: pop ? 'scale(1.15)' : 'scale(1)',
          transition: 'transform 0.15s ease',
        }}
      >
        <span style={{ fontSize: 18 }}>{liked ? '♥' : '♡'}</span>
        {count}
      </button>
      {error && <p style={{ color: '#dc2626', fontSize: 13 }}>Couldn't save — reverted.</p>}
    </div>
  );
}

