import { Component, Input, OnInit } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-like-button',
  template: `
    <div>
      <button
        (click)="toggle()"
        [attr.aria-pressed]="liked"
        [class.liked]="liked"
        [class.pop]="pop"
        class="like"
        [style.cursor]="busy ? 'wait' : 'pointer'"
      >
        <span class="icon">{{ liked ? '♥' : '♡' }}</span>
        {{ count }}
      </button>
      <p *ngIf="error" class="err">Couldn't save — reverted.</p>
    </div>
  `,
  styles: [`
    .like { display: inline-flex; align-items: center; gap: 8px; padding: 8px 16px; font-size: 16px; border: 1px solid #e5e7eb; border-radius: 999px; background: #fff; color: #374151; transition: transform 0.15s ease; }
    .like.liked { background: #fee2e2; color: #dc2626; }
    .like.pop { transform: scale(1.15); }
    .icon { font-size: 18px; }
    .err { color: #dc2626; font-size: 13px; }
  `],
})
export class LikeButtonComponent implements OnInit {
  @Input() initialCount = 0;
  liked = false;
  count = 0;
  busy = false;
  pop = false;
  error = false;

  ngOnInit(): void {
    this.count = this.initialCount;
  }

  fakeLike(): Promise<void> {
    return new Promise((resolve, reject) => {
      setTimeout(() => (Math.random() < 0.9 ? resolve() : reject(new Error('network'))), 400);
    });
  }

  toggle(): void {
    if (this.busy) {
      return;
    }
    const prevLiked = this.liked;
    const prevCount = this.count;

    this.liked = !this.liked;
    this.count += this.liked ? 1 : -1;
    this.error = false;
    if (this.liked) {
      this.pop = true;
      setTimeout(() => (this.pop = false), 200);
    }

    this.busy = true;
    this.fakeLike()
      .then(() => {
        this.busy = false;
      })
      .catch(() => {
        this.liked = prevLiked;
        this.count = prevCount;
        this.error = true;
        this.busy = false;
      });
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Like Button Demo</h1>
      <app-like-button [initialCount]="42"></app-like-button>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, LikeButtonComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
